    public boolean load(String xmlContent) {
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            return false;
        }

        Digester digester = new Digester();

        // Security: Configure features to prevent XXE (XML External Entity) attacks
        try {
            // This is the most secure way to prevent XXE, but it might not be supported by all parsers
            digester.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        } catch (Exception e) {
            // Fallback for parsers that do not support the strict feature above
            try {
                digester.setFeature("http://xml.org/sax/features/external-general-entities", false);
                digester.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            } catch (Exception ignored) {
                // Log warning if features cannot be set
            }
        }

        // We don't need rules for validation, just the parsing mechanism.
        // Digester will throw SAXException if the XML is malformed.
        try (InputStream inputStream = new ByteArrayInputStream(xmlContent.getBytes(StandardCharsets.UTF_8))) {
            digester.parse(inputStream);
            return true;
        } catch (IOException | SAXException e) {
            // Invalid XML format or IO error
            return false;
        }
    }
}
